'use client'
import BlackScreenBackground from '@/components/BlackScreenBackground';
import { useModal } from '@/hooks/useModal';

interface ModalRootProps {
  children: React.ReactNode;
}

export default function ModalRoot({ children }: ModalRootProps) {
  const { isOpen, setIsOpen } = useModal();
  return (
    <>
      {isOpen && (
        <>
          <BlackScreenBackground onClick={() => setIsOpen(false)} />
          <article className="fixed top-50">{children}</article>
        </>
      )}
    </>
  );
}
